import{_ as t}from"./chunks/subs-usage-warning.Bdji-M7h.js";import{_ as a,o,c as r,a0 as s}from"./chunks/framework.jwovEGr5.js";const m=JSON.parse('{"title":"Quota Warnings & Exceeded Limits","description":"","frontmatter":{},"headers":[],"relativePath":"subscriptions/quota-warnings.md","filePath":"subscriptions/quota-warnings.md"}'),n={name:"subscriptions/quota-warnings.md"};function i(l,e,h,u,d,p){return o(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="quota-warnings-exceeded-limits" tabindex="-1">Quota Warnings &amp; Exceeded Limits <a class="header-anchor" href="#quota-warnings-exceeded-limits" aria-label="Permalink to &quot;Quota Warnings &amp; Exceeded Limits&quot;">​</a></h1><p>Every plan sets a <strong><a href="./../getting-started/glossary.html#quota--limit">quota</a></strong> — a ceiling — on each kind of resource: players, events, event instances, results, screenshots, storage space, imports, and users. As you fill a resource up, the app warns you before you run out, and stops you if you hit the ceiling. This page explains the warning levels and what to do.</p><h2 id="where-you-see-it" tabindex="-1">Where you see it <a class="header-anchor" href="#where-you-see-it" aria-label="Permalink to &quot;Where you see it&quot;">​</a></h2><p>Your <strong>Subscription &amp; Usage panel</strong> shows a bar for each resource with how much of the limit you&#39;ve used, a percentage, and a status. It&#39;s on the kingdom detail page (Kings), the <a href="./../how-to/my-alliance.html">My Alliance</a> page (Leaders and Co-Leaders), and everywhere for Supreme Admins.</p><p><img src="'+t+'" alt="Usage panel showing warning and exceeded resources"></p><h2 id="the-warning-levels" tabindex="-1">The warning levels <a class="header-anchor" href="#the-warning-levels" aria-label="Permalink to &quot;The warning levels&quot;">​</a></h2><p>Each resource has a status based on how full it is:</p><table tabindex="0"><thead><tr><th>Level</th><th>How full</th><th>What it means</th></tr></thead><tbody><tr><td><strong>OK</strong></td><td>under 80%</td><td>Plenty of room. Nothing to do.</td></tr><tr><td><strong>Warning</strong></td><td>80% or more</td><td>Getting close. A good time to tidy up or plan an upgrade.</td></tr><tr><td><strong>Critical</strong></td><td>95% or more</td><td>Almost full. Act soon to avoid being blocked.</td></tr><tr><td><strong>Exceeded</strong></td><td>100% (full)</td><td>You&#39;ve hit the ceiling. You can&#39;t add more of this resource until you free some up or raise the limit.</td></tr></tbody></table><p>The panel shows banners for anything at Warning or above, so you&#39;re never surprised.</p><h2 id="what-exceeded-blocks" tabindex="-1">What &quot;Exceeded&quot; blocks <a class="header-anchor" href="#what-exceeded-blocks" aria-label="Permalink to &quot;What &quot;Exceeded&quot; blocks&quot;">​</a></h2><p>When a resource is <strong>Exceeded (100%)</strong>, the app stops you from creating <strong>more of that specific resource</strong>. For example, hitting the player limit blocks adding new players — but doesn&#39;t stop you from viewing analytics or working with what you already have. Other resources that aren&#39;t full keep working normally.</p><h2 id="what-to-do-about-warnings" tabindex="-1">What to do about warnings <a class="header-anchor" href="#what-to-do-about-warnings" aria-label="Permalink to &quot;What to do about warnings&quot;">​</a></h2><p>You have three options, in rough order of effort:</p><ol><li><strong>Free up space.</strong> Delete things you no longer need — old imports, unused players — to drop back under the limit. See <a href="./cleanup.html">Run a Cleanup</a>, which also surfaces the app&#39;s own suggestions for what to remove.</li><li><strong>Ask for more room.</strong> Request a <strong><a href="./request-subscription.html">quota increase</a></strong> (stay on your plan, get a higher ceiling) from a Supreme Admin.</li><li><strong>Upgrade your plan.</strong> Move to a premium plan with higher limits — see <a href="./plans.html">Plans &amp; Tiers</a> and <a href="./request-subscription.html">Request a Subscription</a>.</li></ol><h2 id="if-you-go-over-a-hard-limit" tabindex="-1">If you go over a hard limit <a class="header-anchor" href="#if-you-go-over-a-hard-limit" aria-label="Permalink to &quot;If you go over a hard limit&quot;">​</a></h2><p>Filling a resource all the way can trigger <strong>limited (cleanup) mode</strong>, where the kingdom or alliance is temporarily restricted until usage drops back down. This is closely tied to <a href="./suspension.html">suspension</a> — read that page for exactly what limited mode does and how the app lifts it once you clean up.</p><h2 id="cleanup-suggestions" tabindex="-1">Cleanup suggestions <a class="header-anchor" href="#cleanup-suggestions" aria-label="Permalink to &quot;Cleanup suggestions&quot;">​</a></h2><p>The usage panel doesn&#39;t just warn you — for premium scopes it can also <strong>suggest what to clean up</strong>. These recommendations point at likely candidates for removal so you can get back under a limit quickly. See <a href="./cleanup.html">Run a Cleanup</a>.</p><h2 id="where-to-go-next" tabindex="-1">Where to go next <a class="header-anchor" href="#where-to-go-next" aria-label="Permalink to &quot;Where to go next&quot;">​</a></h2><ul><li><a href="./cleanup.html">Run a Cleanup</a> — free up space and use the app&#39;s suggestions.</li><li><a href="./suspension.html">Suspension &amp; Limited Mode</a> — what happens if a hard limit is reached.</li><li><a href="./request-subscription.html">Request a Subscription</a> — ask for more room or a bigger plan.</li></ul>',20)])])}const f=a(n,[["render",i]]);export{m as __pageData,f as default};
